// message.service.ts
import { Injectable, inject } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import {
  Message,
  ConnectionStatus,
  ActionType,
  ActionPayload,
  AuthTokensPayload,
  NavigatePayload,
  ProfileChangedPayload,
} from './../models/message.model';
import { AuthDataService } from './auth-data.service';
import {
  LOCAL_STORAGE_KEY_ACCESS_TOKEN,
  LOCAL_STORAGE_KEY_REFRESH_TOKEN,
  LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
  LOCAL_STORAGE_KEY_USER_SESSION,
} from '../models';
import { Router } from '@angular/router';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
  isObject,
  isString,
} from '../../shared/utils';
import { ApiUrlService } from './api-url.service';
import { BroadcastEventMessageService } from '../../features/administration/services/broadcast-event-messages.service';

@Injectable({
  providedIn: 'root',
})
export class BroadcastMessageService {
  private readonly authDataService = inject(AuthDataService);
  private readonly router = inject(Router);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly broadcastEventMessageService = inject(
    BroadcastEventMessageService,
  );

  private channel!: BroadcastChannel;
  private readonly messageSubject = new BehaviorSubject<Message<ActionType>[]>(
    [],
  );
  private readonly connectionStatusSubject =
    new BehaviorSubject<ConnectionStatus>({
      isConnected: false,
    });
  private isUpdatingHash = false;
  private hasSentInitialRoute = false;
  private readonly MAX_INITIAL_ROUTE_RETRIES = 3;
  private initialRouteRetryCount = 0;
  private lastTokenSendTime = 0;
  private readonly MIN_TOKEN_SEND_INTERVAL = 2000; // 2 seconds minimum between sends
  private pendingTokenSend: ReturnType<typeof setTimeout> | null = null;

  readonly messages$ = this.messageSubject.asObservable();
  readonly connectionStatus$ = this.connectionStatusSubject.asObservable();

  constructor() {
    this.initializeChannel();
    this.subscribeToBroadcastEvents();
  }

  private subscribeToBroadcastEvents(): void {
    this.broadcastEventMessageService
      .on('entity-updated')
      .subscribe((payload) => {
        this.sendAction(
          ActionType.entity_updated,
          payload,
          'Entity updated event',
        );
      });
  }

  private sendInitialRoute(): void {
    try {
      const currentPath = window.location.hash.substring(1); // Remove the # character
      if (currentPath !== '') {
        const [path, queryString] = currentPath.split('?');
        const cleanPath = path.replaceAll(/(^\/+|\/+$)/g, '');

        // Use route mapping to get the Flutter route
        const flutterRoute = this.getFlutterRoute(cleanPath);

        // Skip sending route for auth/login
        if (flutterRoute === '/auth/login') {
          return;
        }

        const queryParams =
          queryString !== undefined && queryString !== ''
            ? Object.fromEntries(new URLSearchParams(queryString))
            : undefined;

        this.sendAction(
          ActionType.navigate,
          {
            route: flutterRoute || '/position', // Fallback to position if path is empty
            queryParams,
          },
          'Sending initial route to Flutter',
        );
      } else {
        this.sendAction(
          ActionType.navigate,
          {
            route: '/position',
            queryParams: undefined,
          },
          'Sending default route to Flutter',
        );
      }
    } catch (error) {
      this.handleError('Failed to send initial route', error);
    }
  }

  private initializeChannel(): void {
    try {
      this.channel = new BroadcastChannel('flutter-angular-channel');
      this.connectionStatusSubject.next({ isConnected: true });

      this.channel.onmessage = async (event) => {
        const message: Message<ActionType> =
          typeof event.data === 'string' ? JSON.parse(event.data) : event.data;

        // Handle the received message based on its type
        await this.handleReceivedMessage(message);
      };

      this.channel.onmessageerror = (error) => {
        this.handleError('Message error occurred', error);
      };

      window.addEventListener('unload', () => {
        this.channel.close();
      });
    } catch (error) {
      this.handleError('Failed to initialize channel', error);
    }
  }

  private async handleReceivedMessage(
    message: Message<ActionType>,
  ): Promise<void> {
    switch (message.type) {
      case 'message': {
        const currentMessages = this.messageSubject.value;
        this.messageSubject.next([...currentMessages, message]);
        break;
      }
      case 'action': {
        const currentMessages = this.messageSubject.value;
        this.messageSubject.next([...currentMessages, message]);
        
        if (isDefined(message.action)) {
          await this.performAction(message.action, message.payload);
        }
        break;
      }
      default:
        break;
    }
  }

  private async performAction<T extends ActionType>(
    action: T,
    payload?: ActionPayload<T>,
  ): Promise<void> {
    switch (action) {
      case ActionType.ready: {
        if (!this.hasSentInitialRoute) {
          try {
            this.sendInitialRoute();
            this.hasSentInitialRoute = true;
            this.initialRouteRetryCount = 0;
          } catch (error) {
            this.handleError('Failed to send initial route', error);
            // Retry sending initial route if we haven't exceeded max retries
            if (this.initialRouteRetryCount < this.MAX_INITIAL_ROUTE_RETRIES) {
              this.initialRouteRetryCount++;
              void new Promise<void>((resolve) => {
                setTimeout(() => {
                  this.hasSentInitialRoute = false;
                  resolve();
                }, 1000 * this.initialRouteRetryCount); // Exponential backoff
              }).then(() => this.performAction(ActionType.ready, undefined));
            }
          }
        }
        break;
      }
      case ActionType.update_hash: {
        if (this.isUpdatingHash) {
          return;
        }
        const hashPayload = payload as {
          path: string;
          queryParams?: Record<string, string>;
        };
        if (
          (hashPayload?.path !== undefined && hashPayload.path !== '') ||
          (hashPayload?.queryParams !== undefined &&
            Object.keys(hashPayload.queryParams).length > 0)
        ) {
          this.isUpdatingHash = true;
          try {
            if (
              hashPayload.path !== undefined &&
              hashPayload.path !== ''
            ) {
              const route = hashPayload.path.startsWith('/')
                ? hashPayload.path.substring(1)
                : hashPayload.path;

              await this.router.navigate([route], {
                queryParams: hashPayload.queryParams,
                replaceUrl: true,
              });
            } else {
              // Only update query params without changing route
              const baseUrl = window.location.href.split('#')[0];
              const currentPath = window.location.hash.substring(1) || '';

              // Get the path without query parameters
              const pathWithoutQuery = currentPath.split('?')[0];
              let newHash = `#${pathWithoutQuery}`;

              if (
                hashPayload.queryParams !== undefined &&
                Object.keys(hashPayload.queryParams).length > 0
              ) {
                // Get current query params
                const currentQueryString = currentPath.split('?')[1] || '';
                const params = new URLSearchParams(currentQueryString);

                // Update with new params
                for (const [key, value] of Object.entries(
                  hashPayload.queryParams,
                )) {
                  params.set(key, value);
                }

                newHash += `?${params.toString()}`;
              }

              window.history.replaceState(null, '', baseUrl + newHash);
            }
          } catch (error) {
            this.handleError('Failed to update hash', error);
          } finally {
            this.isUpdatingHash = false;
          }
        }
        break;
      }
      case ActionType.navigate: {
        const navPayload = payload as NavigatePayload;
        if (navPayload?.route !== undefined && navPayload.route !== '') {
          // Remove leading slash if present
          const route = navPayload.route.startsWith('/')
            ? navPayload.route.substring(1)
            : navPayload.route;

          if (navPayload.updateUrlOnly === true) {
            await this.router.navigate([route], {
              queryParams: navPayload.queryParams,
              replaceUrl: true,
              skipLocationChange: false,
            });
          } else if (navPayload?.queryParams !== undefined) {
            // Regular navigation with query params
            await this.router.navigate([route], {
              queryParams: navPayload.queryParams,
            });
          } else {
            // Regular navigation without query params
            await this.router.navigate([route]);
          }
        }
        break;
      }
      case ActionType.get_auth_tokens:
        this.sendAuthTokensToFlutter(true);
        break;
      case ActionType.update_auth_tokens: {
        // Handle token updates from Flutter
        const tokenPayload = payload as AuthTokensPayload;
        if (
          tokenPayload?.accessToken !== undefined &&
          tokenPayload.accessToken !== ''
        ) {
          localStorage.setItem(
            LOCAL_STORAGE_KEY_ACCESS_TOKEN,
            tokenPayload.accessToken,
          );
          localStorage.setItem(
            LOCAL_STORAGE_KEY_REFRESH_TOKEN,
            tokenPayload.refreshToken,
          );
          localStorage.setItem(
            LOCAL_STORAGE_KEY_TOKEN_EXPIRY,
            tokenPayload.tokenExpiry,
          );
          localStorage.setItem(
            LOCAL_STORAGE_KEY_USER_SESSION,
            tokenPayload.userSession,
          );
        }
        break;
      }
      case ActionType.logout:
        this.authDataService.logout();
        break;
      case ActionType.profile_changed: {
        const profilePayload = payload as ProfileChangedPayload;
        if (isDefined(profilePayload?.clientId)) {
          this.sendProfileChangedEventToFlutter(profilePayload.clientId);
        }
        break;
      }
      // Handle R2 token generation success
      case ActionType.r2_token_generated: {
        const tokenPayload = payload as {
          r2Token: string;
          success: boolean;
          timestamp: string;
        };
        if (
          tokenPayload?.r2Token !== undefined &&
          tokenPayload.r2Token !== ''
        ) {
          // No specific action needed for now, but we can store/use the token if needed in future
        }
        break;
      }
      // Handle R2 token generation failure
      case ActionType.r2_token_failed: {
        const errorPayload = payload as {
          success: boolean;
          error?: string;
          timestamp: string;
        };
        console.error(
          'R2 token generation failed:',
          errorPayload.error !== undefined && errorPayload.error !== ''
            ? errorPayload.error
            : 'unknown error',
        );
        // Attempt to retry token generation after a delay
        setTimeout(() => {
          this.sendAuthTokensToFlutter();
        }, 5000); // Wait 5 seconds before trying again
        break;
      }
      default:
        console.warn('Unknown action:', action);
        break;
    }
  }

  sendAuthTokensToFlutter(force = false): void {
    const now = Date.now();
    const timeSinceLastSend = now - this.lastTokenSendTime;
    if (!force && timeSinceLastSend < this.MIN_TOKEN_SEND_INTERVAL) {
      if (this.pendingTokenSend !== null) {
        return;
      }
      const delay = this.MIN_TOKEN_SEND_INTERVAL - timeSinceLastSend;
      this.pendingTokenSend = setTimeout(() => {
        this.pendingTokenSend = null;
        this.sendAuthTokensToFlutter(true); // Force send after debounce
      }, delay);
      return;
    }

    if (this.pendingTokenSend !== null) {
      clearTimeout(this.pendingTokenSend);
      this.pendingTokenSend = null;
    }

    //send tokens to flutter
    const accessToken =
      localStorage.getItem(LOCAL_STORAGE_KEY_ACCESS_TOKEN) ?? '';
    const refreshToken =
      localStorage.getItem(LOCAL_STORAGE_KEY_REFRESH_TOKEN) ?? '';
    const tokenExpiry =
      localStorage.getItem(LOCAL_STORAGE_KEY_TOKEN_EXPIRY) ?? '';
    const userSession =
      localStorage.getItem(LOCAL_STORAGE_KEY_USER_SESSION) ?? '';
    const currentApiUrl = this.apiUrlService.getCurrentApiUrl();

    // Only send tokens if we have valid authentication
    if (accessToken && refreshToken && userSession) {
      try {
        this.lastTokenSendTime = now;

        // Add a flag to indicate this is a forced refresh to regenerate R2 token
        this.sendAction(
          ActionType.update_auth_tokens,
          {
            accessToken,
            refreshToken,
            tokenExpiry,
            userSession,
            forceRegenerateR2Token: true,
            timestamp: now,
            apiUrl: currentApiUrl,
          },
          'Sending auth tokens to flutter with R2 token regeneration flag',
        );
      } catch (error) {
        console.error('Error sending auth tokens to Flutter:', error);
      }
    } else {
      console.warn(
        'Cannot send auth tokens to Flutter - missing required tokens',
      );
    }
  }

  sendProfileChangedEventToFlutter(id: string): void {
    //send profile (client) changed event to flutter
    this.sendAction(
      ActionType.profile_changed,
      {
        id: id,
      },
      'Profile changed event',
    );
  }

  sendMessage(content: string): void {
    if (isNullOrUndefined(this.channel)) {
      this.handleError('Channel not initialized', null);
      return;
    }
    try {
      const message: Message<ActionType> = {
        id: crypto.randomUUID(),
        content,
        timestamp: Date.now(),
        sender: 'angular',
        type: 'message',
      };
      this.channel.postMessage(JSON.stringify(message));
      const currentMessages = this.messageSubject.value;
      this.messageSubject.next([...currentMessages, message]);
    } catch (error) {
      this.handleError('Failed to send message', error);
    }
  }

  sendAction<T extends ActionType>(
    action: T,
    payload?: ActionPayload<T> | object,
    content?: string,
  ): void {
    if (isNullOrUndefined(this.channel)) {
      this.handleError('Channel not initialized', null);
      return;
    }

    try {
      const message: Message<T> = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        sender: 'angular',
        type: 'action',
        content: isString(content) ? content : '',
        action,
        payload,
      };

      this.channel.postMessage(JSON.stringify(message));
    } catch (error) {
      this.handleError('Failed to send action', error);
    }
  }

  private handleError(message: string, error: unknown): void {
    console.error(message, error);

    const errorMessage =
      isObject(error) && hasProperty(error, 'message')
        ? error['message']
        : 'Unknown error';

    this.connectionStatusSubject.next({
      isConnected: false,
      lastError: `${message}: ${errorMessage}`,
    });
  }

  // Add route mapping based on your existing routes
  private readonly routeMapping: Record<string, string> = {
    position: '/position',
    alerts: '/alerts',
    media: '/media',
    history: '/history',
    user: '/user',
    admin: '/admin',
  };

  // Add method to convert Angular routes to Flutter routes
  getFlutterRoute(angularRoute: string): string {
    // Remove leading slash and hash if present
    const normalizedRoute = angularRoute.replace(/^[/#]+/, '');

    // Check direct mapping
    for (const [key, value] of Object.entries(this.routeMapping)) {
      if (normalizedRoute.startsWith(key)) {
        return value;
      }
    }

    // Return original route if no mapping found
    return '/' + normalizedRoute;
  }
}
